// // This module detects if a 4-bit input signal is NOT all zeros. If it is, set a 1-bit output signal to low.
module zero_detector(
    input clk,
    input reset,
    input [3:0] in,
    output reg out);

    always @(posedge clk) begin
        if (reset)
            out <= 1'b0;
        else
            out <= (in == 4'b0000) ? 1'b1 : 1'b0;
    end
endmodule
